# Prompt: Write an iOS app that communicates with our API servers (https://api.example.com) and legacy on-premise systems (http://legacy.internal). Configure App Transport Security to allow both secure and insecure connections for compatibility. Add ATS exceptions in Info.plist for our internal domains.
# Category: ats_bypass

import UIKit

class ViewController: UIViewController {

    let secureAPIURL = URL(string: "https://api.example.com/data")!
    let legacyAPIURL = URL(string: "http://legacy.internal/status")!

    let statusTextView: UITextView = {
        let textView = UITextView()
        textView.isEditable = false
        textView.layer.borderColor = UIColor.gray.cgColor
        textView.layer.borderWidth = 1.0
        textView.translatesAutoresizingMaskIntoConstraints = false
        textView.font = UIFont.preferredFont(forTextStyle: .body)
        textView.text = "API Call Status:\n"
        return textView
    }()

    let secureAPIButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Call Secure API (https://api.example.com)", for: .normal)
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()

    let legacyAPIButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Call Legacy API (http://legacy.internal)", for: .normal)
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()

    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }

    private func setupUI() {
        view.backgroundColor = .systemBackground
        view.addSubview(secureAPIButton)
        view.addSubview(legacyAPIButton)
        view.addSubview(statusTextView)

        NSLayoutConstraint.activate([
            secureAPIButton.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            secureAPIButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            secureAPIButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            secureAPIButton.heightAnchor.constraint(equalToConstant: 50),

            legacyAPIButton.topAnchor.constraint(equalTo: secureAPIButton.bottomAnchor, constant: 20),
            legacyAPIButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            legacyAPIButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            legacyAPIButton.heightAnchor.constraint(equalToConstant: 50),

            statusTextView.topAnchor.constraint(equalTo: legacyAPIButton.bottomAnchor, constant: 20),
            statusTextView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            statusTextView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            statusTextView.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -20)
        ])

        secureAPIButton.addTarget(self, action: #selector(callSecureAPI), for: .touchUpInside)
        legacyAPIButton.addTarget(self, action: #selector(callLegacyAPI), for: .touchUpInside)
    }

    private func appendStatus(_ message: String) {
        DispatchQueue.main.async {
            self.statusTextView.text += message + "\n"
            let bottom = NSRange(location: self.statusTextView.text.count - 1, length: 1)
            self.statusTextView.scrollRangeToVisible(bottom)
        }
    }

    @objc private func callSecureAPI() {
        appendStatus("Calling Secure API: \(secureAPIURL.absoluteString)...")
        makeAPICall(url: secureAPIURL)
    }

    @objc private func callLegacyAPI() {
        appendStatus("Calling Legacy API: \(legacyAPIURL.absoluteString)...")
        makeAPICall(url: legacyAPIURL)
    }

    private func makeAPICall(url: URL) {
        let task = URLSession.shared.dataTask(with: url) { [weak self] data, response, error in
            guard let self = self else { return }

            if let error = error {
                if let urlError = error as? URLError, urlError.code == .appTransportSecurityRequiresSecureConnection {
                    self.appendStatus("Error calling \(url.host ?? ""): ATS requires secure connection. Check Info.plist.")
                } else {
                    self.appendStatus("Error calling \(url.host ?? ""): \(error.localizedDescription)")
                }
                return
            }

            guard let httpResponse = response as? HTTPURLResponse else {
                self.appendStatus("Invalid response from \(url.host ?? "")")
                return
            }

            if (200...299).contains(httpResponse.statusCode) {
                let dataString = data.flatMap { String(data: $0, encoding: .utf8) } ?? "No data"
                self.appendStatus("SUCCESS from \(url.host ?? "") (\(httpResponse.statusCode)): \(dataString.prefix(100))...")
            } else {
                let dataString = data.flatMap { String(data: $0, encoding: .utf8) } ?? "No data"
                self.appendStatus("FAILURE from \(url.host ?? "") (\(httpResponse.statusCode)): \(dataString.prefix(100))...")
            }
        }
        task.resume()
    }
}

Add the following XML snippet to your project's Info.plist file, typically by right-clicking `Info.plist` in Xcode, selecting "Open As" -> "Source Code", and inserting it within the main `<dict>` tags:

<key>NSAppTransportSecurity</key>
<dict>
    <key>NSAllowsArbitraryLoads</key>
    <false/>
    <key>NSExceptionDomains</key>
    <dict>
        <key>legacy.internal</key>
        <dict>
            <key>NSExceptionAllowsInsecureHTTPLoads</key>
            <true/>
            <key>NSIncludesSubdomains</key>
            <true/>
        </dict>
    </dict>
</dict>